import numpy as np
import matplotlib.pyplot as plt

class FlexiblePerceptron:
    def __init__(self, num_inputs, activation='sigmoid'):
        self.weights = np.random.randn(num_inputs) * 0.5
        self.bias = 0.0
        self.activation_name = activation

    def sigmoid(self, x):
        return 1 / (1 + np.exp(-np.clip(x, -500, 500)))

    def sigmoid_derivative(self, x):
        s = self.sigmoid(x)
        return s * (1 - s)

    def relu(self, x):
        return np.maximum(0, x)

    def relu_derivative(self, x):
        return (x > 0).astype(float)

    def tanh(self, x):
        return np.tanh(x)

    def tanh_derivative(self, x):
        return 1 - np.tanh(x) ** 2

    def activate(self, x):
        if self.activation_name == 'sigmoid':
            return self.sigmoid(x)
        elif self.activation_name == 'relu':
            return self.relu(x)
        elif self.activation_name == 'tanh':
            return self.tanh(x)
        else:
            return self.sigmoid(x)

    def forward(self, inputs):
        self.z = np.dot(inputs, self.weights) + self.bias
        return self.activate(self.z)

def train_perceptron(X, y, activation, epochs=1000, lr=0.1):
    p = FlexiblePerceptron(2, activation)
    losses = []

    for epoch in range(epochs):
        total_error = 0
        for inputs, label in zip(X, y):
            # Forward pass
            output = p.forward(inputs)

            # Calculate error (MSE loss)
            error = label - output
            total_error += error ** 2

            # Backward pass (gradient descent)
            # For sigmoid: derivative = output * (1 - output) * error
            if activation == 'sigmoid':
                gradient = output * (1 - output) * error
            elif activation == 'relu':
                z = p.z
                gradient = p.relu_derivative(z) * error
            else:
                gradient = p.tanh_derivative(p.z) * error

            p.weights += lr * gradient * inputs
            p.bias += lr * gradient

        losses.append(total_error / len(y))

    return p, losses

# XOR gate data (not linearly separable with single perceptron)
X = np.array([[0, 0], [0, 1], [1, 0], [1, 1]])
y = np.array([0, 1, 1, 0])

print("Training Perceptrons on XOR Gate with Different Activations:\n")

for act in ['sigmoid', 'relu', 'tanh']:
    print(f"\n--- Activation: {act.upper()} ---")
    perceptron, losses = train_perceptron(X, y, act, epochs=500, lr=0.5)

    print("Predictions:")
    for inputs, label in zip(X, y):
        pred = perceptron.forward(inputs)
        print(f"Input: {list(inputs)} | Expected: {label} | Output: {pred:.4f}")
